+			}
+			_ = json.NewEncoder(w).Encode(map[string]any{
+				"id": "f-retried",
+				"criteria": map[string]any{
+					"query": "subject:\"retry-me\"",
+				},
+				"action": map[string]any{
+					"removeLabelIds": []string{"INBOX"},
+				},
+			})
+			return
+		default:
+			http.NotFound(w, r)
+		}
+	}))
